61	/// # Examples
62	/// ```
63	/// use std::sync::Arc;
64	/// use std::time::Duration;
65	/// use zenoh_protocol::core::{ZenohIdProto, Resolution, Field, Bits, WhatAmI, whatami};
66	/// use zenoh_transport::*;
67	/// use zenoh_result::ZResult;
68	///
69	/// // Create my transport handler to be notified when a new transport is initiated with me
70	/// #[derive(Default)]
71	/// struct MySH;
72	///
73	/// impl TransportEventHandler for MySH {
74	///     fn new_unicast(&self,
75	///         _peer: TransportPeer,
76	///         _transport: unicast::TransportUnicast
77	///     ) -> ZResult<Arc<dyn TransportPeerEventHandler>> {
78	///         Ok(Arc::new(DummyTransportPeerEventHandler))
79	///     }
80	///
81	///     fn new_multicast(
82	///         &self,
83	///         _transport: multicast::TransportMulticast,
84	///     ) -> ZResult<Arc<dyn TransportMulticastEventHandler>> {
85	///         Ok(Arc::new(DummyTransportMulticastEventHandler))
86	///     }
87	/// }
88	///
89	/// // Create the default TransportManager
90	/// let manager = TransportManager::builder()
91	///         .build(Arc::new(MySH::default()))
92	///         .unwrap();
93	///
94	/// // Create the TransportManager with custom configuration
95	/// // Configure the unicast transports parameters
96	/// let unicast = TransportManager::config_unicast()
97	///         .lease(Duration::from_secs(1))
98	///         .keep_alive(4)      // Send a KeepAlive every 250 ms
99	///         .accept_timeout(Duration::from_secs(1))
100	///         .accept_pending(10) // Set to 10 the number of simultaneous pending incoming transports
101	///         .max_sessions(5);   // Allow max 5 transports open
102	/// let mut resolution = Resolution::default();
103	/// resolution.set(Field::FrameSN, Bits::U8);
104	/// let manager = TransportManager::builder()
105	///         .zid(ZenohIdProto::rand().into())
106	///         .whatami(WhatAmI::Peer)
107	///         .batch_size(1_024)              // Use a batch size of 1024 bytes
108	///         .resolution(resolution)         // Use a sequence number resolution of 128
109	///         .unicast(unicast)               // Configure unicast parameters
110	///         .build(Arc::new(MySH::default()))
111	///         .unwrap();
112	/// ```
