394	    pub async fn from_config(
395	        mut self,
396	        config: &ExpandedConfig,
397	    ) -> ZResult<TransportManagerBuilder> {
398	        self = self.zid(config.id().into());
399	        self = self.whatami(config.mode());
400	
401	        let link = config.transport().link();
402	        let cc_drop = link.tx().queue().congestion_control().drop();
403	        let cc_block = link.tx().queue().congestion_control().block();
404	        let mut resolution = Resolution::default();
405	        resolution.set(Field::FrameSN, *link.tx().sequence_number_resolution());
406	        self = self.resolution(resolution);
407	        self = self.batch_size(*link.tx().batch_size());
408	        self = self.batching_enabled(*link.tx().queue().batching().enabled());
409	        self = self.batching_time_limit(Duration::from_millis(
410	            *link.tx().queue().batching().time_limit(),
411	        ));
412	        self = self.defrag_buff_size(*link.rx().max_message_size());
413	        self = self.link_rx_buffer_size(*link.rx().buffer_size());
414	        self = self.wait_before_drop(duration_from_i64us(*cc_drop.wait_before_drop()));
415	        self = self.max_wait_before_drop_fragments(duration_from_i64us(
416	            *cc_drop.max_wait_before_drop_fragments(),
417	        ));
418	        self = self.wait_before_close(duration_from_i64us(*cc_block.wait_before_close()));
419	        self = self.queue_size(link.tx().queue().size().clone());
420	        self = self.queue_alloc(*link.tx().queue().allocation());
421	        self = self.tx_threads(*link.tx().threads());
422	        self = self.protocols(link.protocols().clone());
423	        self = self.region_name(config.region_name().clone());
424	
425	        #[cfg(feature = "shared-memory")]
426	        {
427	            self = self.shm(config.transport().shared_memory().clone());
428	        }
429	
430	        let (c, errors) = zenoh_link::LinkConfigurator::default().configurations(config);
431	        if !errors.is_empty() {
432	            use std::fmt::Write;
433	            let mut formatter = String::from("Some protocols reported configuration errors:\r\n");
434	            for (proto, err) in errors {
435	                write!(&mut formatter, "\t{proto:?}: {err}\r\n")?;
436	            }
437	            bail!("{}", formatter);
438	        }
439	        self = self.link_configs(c);
440	        self = self.unicast(
441	            TransportManagerBuilderUnicast::default()
442	                .from_config(config)
443	                .await?,
444	        );
445	        self = self.multicast(TransportManagerBuilderMulticast::default().from_config(config)?);
446	
447	        Ok(self)
448	    }
