450	    pub fn build(
451	        self,
452	        handler: Arc<dyn TransportEventHandler>,
453	        #[cfg(feature = "stats")] stats: zenoh_stats::StatsRegistry,
454	    ) -> ZResult<TransportManager> {
455	        // Initialize the PRNG and the Cipher
456	        let mut prng = PseudoRng::from_entropy();
457	
458	        #[cfg(feature = "shared-memory")]
459	        let shm_context = ShmContext::new(self.shm, self.shm_reader)?;
460	
461	        let unicast = self.unicast.build(&mut prng)?;
462	        let multicast = self.multicast.build()?;
463	
464	        let mut queue_size = [0; Priority::NUM];
465	        queue_size[Priority::Control as usize] = *self.queue_size.control();
466	        queue_size[Priority::RealTime as usize] = *self.queue_size.real_time();
467	        queue_size[Priority::InteractiveHigh as usize] = *self.queue_size.interactive_high();
468	        queue_size[Priority::InteractiveLow as usize] = *self.queue_size.interactive_low();
469	        queue_size[Priority::DataHigh as usize] = *self.queue_size.data_high();
470	        queue_size[Priority::Data as usize] = *self.queue_size.data();
471	        queue_size[Priority::DataLow as usize] = *self.queue_size.data_low();
472	        queue_size[Priority::Background as usize] = *self.queue_size.background();
473	
474	        let config = TransportManagerConfig {
475	            version: self.version,
476	            zid: self.zid,
477	            whatami: self.whatami,
478	            resolution: self.resolution,
479	            batch_size: self.batch_size,
480	            batching: self.batching_enabled,
481	            wait_before_drop: self.wait_before_drop,
482	            max_wait_before_drop_fragments: self.max_wait_before_drop_fragments,
483	            wait_before_close: self.wait_before_close,
484	            queue_size,
485	            queue_backoff: self.batching_time_limit,
486	            queue_alloc: self.queue_alloc,
487	            defrag_buff_size: self.defrag_buff_size,
488	            link_rx_buffer_size: self.link_rx_buffer_size,
489	            unicast: unicast.config,
490	            multicast: multicast.config,
491	            link_configs: self.link_configs,
492	            handler,
493	            tx_threads: self.tx_threads,
494	            supported_links: self
495	                .supported_links
496	                .unwrap_or_else(|| zenoh_link::ALL_SUPPORTED_LINKS.to_vec()),
497	            bound_callback: self.bound_callback,
498	            region_name: self.region_name,
499	        };
500	
501	        let state = TransportManagerState {
502	            unicast: unicast.state,
503	            multicast: multicast.state,
504	            #[cfg(feature = "shared-memory")]
505	            shm_context,
506	            #[cfg(all(feature = "uring", target_os = "linux"))]
507	            uring: Uring::new(config.batch_size as usize, config.link_rx_buffer_size)
508	                .map_err(|e| {
509	                    tracing::warn!("io_uring reactor init failed, falling back to tokio RX: {e}");
510	                    e
511	                })
512	                .ok(),
513	        };
514	
515	        let params = TransportManagerParams { config, state };
516	
517	        Ok(TransportManager::new(
518	            params,
519	            prng,
520	            #[cfg(feature = "stats")]
521	            stats,
522	        ))
523	    }
