580	    pub(crate) prng: Arc<AsyncMutex<PseudoRng>>,
581	    pub(crate) cipher: Arc<BlockCipher>,
582	    pub(crate) locator_inspector: zenoh_link::LocatorInspector,
583	    pub(crate) new_unicast_link_sender: NewLinkChannelSender,
584	    #[cfg(feature = "stats")]
585	    pub(crate) stats: zenoh_stats::StatsRegistry,
586	    pub(crate) task_controller: TaskController,
587	}
588	
589	impl fmt::Debug for TransportManager {
590	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
591	        let mut debug = f.debug_struct("TransportManager");
592	        debug
593	            .field("config", &self.config)
594	            .field("state", &self.state)
595	            .field("prng", &"..")
596	            .field("cipher", &"..")
597	            .field("locator_inspector", &self.locator_inspector)
598	            .field("new_unicast_link_sender", &self.new_unicast_link_sender);
599	        #[cfg(feature = "stats")]
600	        debug.field("stats", &self.stats);
601	        debug
602	            .field("task_controller", &self.task_controller)
603	            .finish()
604	    }
605	}
606	
607	impl TransportManager {
608	    pub fn new(
609	        params: TransportManagerParams,
610	        mut prng: PseudoRng,
611	        #[cfg(feature = "stats")] stats: zenoh_stats::StatsRegistry,
612	    ) -> TransportManager {
613	        // Initialize the Cipher
614	        let mut key = [0_u8; BlockCipher::BLOCK_SIZE];
615	        prng.fill_bytes(&mut key);
616	        let cipher = BlockCipher::new(key);
617	
618	        // @TODO: this should be moved into the unicast module
619	        let (new_unicast_link_sender, new_unicast_link_receiver) = flume::unbounded();
620	
621	        let this = TransportManager {
622	            config: Arc::new(params.config),
623	            state: Arc::new(params.state),
624	            prng: Arc::new(AsyncMutex::new(prng)),
625	            cipher: Arc::new(cipher),
626	            locator_inspector: Default::default(),
627	            new_unicast_link_sender,
628	            #[cfg(feature = "stats")]
629	            stats,
630	            task_controller: TaskController::default(),
631	        };
632	
633	        // @TODO: this should be moved into the unicast module
634	        let cancellation_token = this.task_controller.get_cancellation_token();
635	        this.task_controller
636	            .spawn_with_rt(zenoh_runtime::ZRuntime::Net, {
637	                let this = this.clone();
638	                async move {
639	                    loop {
640	                        tokio::select! {
641	                                res = new_unicast_link_receiver.recv_async() => {
642	                                    if let Ok(new_link) = res {
643	                                        this.handle_new_link_unicast(new_link).await;
644	                                    }
645	                                }
646	                                _ = cancellation_token.cancelled() => { break; }
647	                        }
648	                    }
649	                }
650	            });
651	
652	        this
653	    }
654	
655	    pub fn builder() -> TransportManagerBuilder {
656	        TransportManagerBuilder::default()
657	    }
658	
659	    pub fn zid(&self) -> ZenohIdProto {
660	        self.config.zid
661	    }
662	
663	    #[cfg(feature = "stats")]
664	    pub fn stats(&self) -> &zenoh_stats::StatsRegistry {
665	        &self.stats
666	    }
667	
668	    #[cfg(feature = "shared-memory")]
669	    pub fn get_shm_context(&self) -> &Option<ShmContext> {
670	        &self.state.shm_context
671	    }
672	
673	    pub async fn close(&self) {
674	        self.close_unicast().await;
675	        self.close_multicast().await;
676	        self.task_controller.terminate_all_async().await;
677	    }
678	
679	    /*************************************/
680	    /*              LISTENER             */
681	    /*************************************/
682	    pub async fn add_listener(&self, endpoint: EndPoint) -> ZResult<Locator> {
683	        if self
684	            .locator_inspector
685	            .is_multicast(&endpoint.to_locator())
686	            .await?
687	        {
688	            self.add_listener_multicast(endpoint).await
689	        } else {
690	            self.add_listener_unicast(endpoint).await
691	        }
692	    }
693	
694	    pub async fn del_listener(&self, endpoint: &EndPoint) -> ZResult<()> {
695	        if self
696	            .locator_inspector
697	            .is_multicast(&endpoint.to_locator())
698	            .await?
699	        {
700	            self.del_listener_multicast(endpoint).await
701	        } else {
702	            self.del_listener_unicast(endpoint).await
703	        }
704	    }
705	
706	    pub async fn get_listeners(&self) -> Vec<EndPoint> {
707	        let mut lsu = self.get_listeners_unicast().await;
708	        let mut lsm = self.get_listeners_multicast().await;
709	        lsu.append(&mut lsm);
710	        lsu
711	    }
712	
713	    // TODO(yuyuan): Can we make this async as above?
714	    pub fn get_locators(&self) -> Vec<Locator> {
715	        let mut lsu = zenoh_runtime::ZRuntime::Net.block_in_place(self.get_locators_unicast());
716	        let mut lsm = zenoh_runtime::ZRuntime::Net.block_in_place(self.get_locators_multicast());
717	        lsu.append(&mut lsm);
718	        lsu
719	    }
720	}
